SELECT PARAM.SEQ, PARAM.RESUME_SEQ, ITEM.ITEM_NAME, ITEM.ITEM_CODE ITEM_CODE_ITEM, ITEM.REMARK ITEM_REMARK, GET_CODE_NAME(ITEM.GROUP_NO, #{lang, jdbcType=VARCHAR}) GROUP_NAME, PKG_EVS_PROCESS.GET_EVS_PARAM_NAME(PARAM.RESUME_SEQ, 'GROUP', PARAM.EVS_GROUP) EVS_GROUP_NAME, PKG_EVS_PROCESS.GET_EVS_PARAM_NAME(PARAM.RESUME_SEQ, 'FAMILY', PARAM.EVS_OCC_GROUP) EVS_OCC_GROUP_NAME, PARAM.ITEM_CODE, PARAM.EVS_GROUP, PARAM.EVS_OCC_GROUP, PARAM.REMARK, TO_CHAR(PARAM.ITEM_SCORE) ITEM_SCORE, PARAM.ACTIVITY, TO_CHAR(PARAM.UPDATE_DATE, 'DD/MM/YYYY HH24:MI') UPDATE_DATE, GET_UPDATED_INFO(PARAM.UPDATED_BY) || ' ' || PARAM.UPDATED_IP UPDATED_BY FROM EVS_ITEM_PARAM PARAM, EVS_ITEM ITEM WHERE PARAM.RESUME_SEQ = ITEM.RESUME_SEQ(+) AND PARAM.ITEM_CODE = ITEM.ITEM_CODE(+) AND PARAM.ACTIVITY <> 2
AND PARAM.RESUME_SEQ = #{resumeSeq, jdbcType=VARCHAR}
AND ITEM.GROUP_NO = #{groupNo, jdbcType=VARCHAR}
AND PARAM.EVS_GROUP = #{evsGroup, jdbcType=VARCHAR}
AND PARAM.EVS_OCC_GROUP = #{evsOccGroup, jdbcType=VARCHAR}
ORDER BY TO_NUMBER(PARAM.SEQ)
